//! bench-prefill — measure the batched-prefill speedup on the Llama path.
//!
//! Time-to-first-token in the sovereign fat-station is dominated by PROMPT
//! PREFILL. The legacy path loops `forward_one` once per prompt token: each
//! step re-fetches + re-dequantizes every layer's quantized weight to do a
//! single mat-VEC. `prefill_chunk` instead runs the whole prompt through
//! `forward_range_chunk` — one GEMM per layer over ALL positions, weight
//! loaded ONCE and reused across every row. This bin times both on a real
//! local gguf and a long prompt, and PROVES they are numerically equivalent
//! (argmax + max-abs logit diff at the last position).
//!
//! Usage:
//!   bench-prefill <knot.gguf> [--prompt-len N] [--tokens csv]
//!
//! Defaults: prompt length 800 (repeated deterministic token pattern inside
//! the model's vocab). The whole point is to make prefill long enough that the
//! per-token tax is visible.
//!
//! Correctness gate: the pipeline is run with resonance_threshold = 1.0 so the
//! FFN resonance shortcut is OFF — the one place the per-token and batched
//! paths can diverge. Under that, the two paths execute the identical kernel
//! sequence and must agree to f32 precision.

use std::env;
use std::time::Instant;

use distributed_inference::loader::KnotWeights;
use distributed_inference::NativeLlamaPipeline;

fn argmax(v: &[f32]) -> (usize, f32) {
    let mut mi = 0usize;
    let mut mv = v[0];
    for (i, &x) in v.iter().enumerate() {
        if x > mv {
            mv = x;
            mi = i;
        }
    }
    (mi, mv)
}

fn main() -> Result<(), String> {
    let args: Vec<String> = env::args().collect();
    if args.len() < 2 {
        return Err(format!(
            "usage: {} <knot.gguf> [--prompt-len N] [--tokens csv]",
            args.first().map(String::as_str).unwrap_or("bench-prefill")
        ));
    }

    let knot_path = args[1].clone();
    let mut prompt_len: usize = 800;
    let mut explicit_tokens: Option<Vec<u32>> = None;
    let mut i = 2;
    while i < args.len() {
        match args[i].as_str() {
            "--prompt-len" => {
                i += 1;
                prompt_len = args
                    .get(i)
                    .ok_or("--prompt-len needs a value")?
                    .parse()
                    .map_err(|e| format!("bad --prompt-len: {e}"))?;
            }
            "--tokens" => {
                i += 1;
                let csv = args.get(i).ok_or("--tokens needs a value")?;
                let toks: Result<Vec<u32>, _> = csv
                    .split(',')
                    .map(|t| t.trim().parse::<u32>())
                    .collect();
                explicit_tokens = Some(toks.map_err(|e| format!("bad --tokens: {e}"))?);
            }
            other => return Err(format!("unknown arg {other:?}")),
        }
        i += 1;
    }

    println!("========================================================");
    println!(" bench-prefill — token-by-token vs batched GEMM prefill");
    println!("   knot : {knot_path}");
    println!("========================================================");

    // 1. Load the knot.
    let t_load = Instant::now();
    let knot = KnotWeights::load(&knot_path)?;
    let (num_layers, vocab_size, hidden_dim, arch) = knot
        .config
        .as_ref()
        .map(|c| {
            (
                c.num_layers,
                c.vocab_size,
                c.hidden_dim,
                c.arch.clone(),
            )
        })
        .unwrap_or((22, 32000, 2048, "llama".into()));
    println!(
        "[load] {} ms  arch={arch} layers={num_layers} hidden={hidden_dim} vocab={vocab_size} tensors={}",
        t_load.elapsed().as_millis(),
        knot.metadata.len()
    );

    // 2. Build the prompt. Deterministic in-vocab pattern (avoids BOS/special
    //    semantics; the prefill kernels are token-agnostic for timing).
    let tokens: Vec<u32> = match explicit_tokens {
        Some(t) => t,
        None => (0..prompt_len)
            .map(|i| ((i * 131 + 7) % vocab_size.max(2)) as u32)
            .collect(),
    };
    let n = tokens.len();
    println!("[prompt] {n} tokens (resonance OFF → lossless-comparable paths)");

    // resonance_threshold = 1.0 → FFN resonance shortcut OFF, so the per-token
    // and batched paths run the identical kernel sequence (the correctness bar).
    let build = || NativeLlamaPipeline::from_knot(
        KnotWeights::load(&knot_path).expect("reload knot"),
        /*draft_mode=*/ false,
        /*resonance_threshold=*/ 1.0,
    );

    // ── Path A: token-by-token prefill (the legacy hot path) ────────────────
    println!("\n[A] token-by-token prefill (loop forward_one)…");
    let mut pa = build();
    let ta = Instant::now();
    for (pos, &tok) in tokens.iter().enumerate() {
        // forward_one uses the EXPLICIT pos arg for RoPE + KV write; this is the
        // same per-position prefill the legacy inner_generate loop performs.
        pa.forward_one(tok as usize, pos, false)
            .map_err(|e| format!("forward_one@{pos}: {e}"))?;
    }
    let a_elapsed = ta.elapsed();
    let logits_a = pa.get_logits().to_vec();
    let a_ms = a_elapsed.as_secs_f64() * 1000.0;
    println!(
        "    {:.1} ms  ({:.3} ms/tok)  positions={}",
        a_ms,
        a_ms / n as f64,
        n
    );

    // ── Path B: batched prefill (prefill_chunk → forward_range_chunk GEMM) ───
    println!("\n[B] batched prefill (prefill_chunk, GEMM per layer)…");
    let mut pb = build();
    let tb = Instant::now();
    pb.prefill_chunk(&tokens, 0)
        .map_err(|e| format!("prefill_chunk: {e}"))?;
    let b_elapsed = tb.elapsed();
    let logits_b = pb.get_logits().to_vec();
    let b_ms = b_elapsed.as_secs_f64() * 1000.0;
    println!(
        "    {:.1} ms  ({:.3} ms/tok)  pos={}",
        b_ms,
        b_ms / n as f64,
        pb.get_pos()
    );

    // ── Correctness: last-position logits must match ────────────────────────
    println!("\n[correctness] last-position logits A (per-token) vs B (batched)");
    assert_eq!(logits_a.len(), logits_b.len(), "logit vector length mismatch");
    let (ia, va) = argmax(&logits_a);
    let (ib, vb) = argmax(&logits_b);
    let mut max_abs = 0.0f32;
    let mut max_idx = 0usize;
    for (k, (&x, &y)) in logits_a.iter().zip(logits_b.iter()).enumerate() {
        let d = (x - y).abs();
        if d > max_abs {
            max_abs = d;
            max_idx = k;
        }
    }
    println!("    argmax A = {ia} (logit {va:.5})");
    println!("    argmax B = {ib} (logit {vb:.5})");
    println!(
        "    argmax agreement : {}",
        if ia == ib { "YES ✓" } else { "NO ✗" }
    );
    println!(
        "    max |Δlogit|     : {:.3e}  (at vocab idx {max_idx}: A={:.5} B={:.5})",
        max_abs, logits_a[max_idx], logits_b[max_idx]
    );

    // ── Interior-position spot check ────────────────────────────────────────
    // Re-run both up to two interior cut points and compare the lm-head readout
    // there, to catch a mask/RoPE/KV-offset bug that only shows mid-sequence.
    if n >= 8 {
        for &cut in &[n / 3, (2 * n) / 3] {
            let pref = &tokens[..cut];
            let mut qa = build();
            for (pos, &tok) in pref.iter().enumerate() {
                qa.forward_one(tok as usize, pos, false)?;
            }
            let la = qa.get_logits().to_vec();
            let mut qb = build();
            qb.prefill_chunk(pref, 0)?;
            let lb = qb.get_logits().to_vec();
            let (ja, _) = argmax(&la);
            let (jb, _) = argmax(&lb);
            let mut md = 0.0f32;
            for (&x, &y) in la.iter().zip(lb.iter()) {
                md = md.max((x - y).abs());
            }
            println!(
                "    interior cut={cut:>4}: argmax {} (A={ja} B={jb})  max|Δ|={md:.3e}",
                if ja == jb { "match" } else { "MISMATCH" }
            );
        }
    }

    // ── Verdict ─────────────────────────────────────────────────────────────
    let speedup = a_ms / b_ms;
    println!("\n========================================================");
    println!(" RESULT");
    println!("   prefill tokens     : {n}");
    println!("   token-by-token     : {a_ms:.1} ms  ({:.3} ms/tok)", a_ms / n as f64);
    println!("   batched (GEMM)     : {b_ms:.1} ms  ({:.3} ms/tok)", b_ms / n as f64);
    println!("   speedup            : {speedup:.2}×");
    println!(
        "   lossless           : {}",
        if ia == ib && max_abs < 1e-2 {
            "YES (argmax match, Δlogit tiny)"
        } else {
            "CHECK — divergence above tolerance"
        }
    );
    println!("========================================================");

    Ok(())
}
